def calculate(principal, rate, time, type, n=12):
    rate_decimal = rate / 100

    if type == 'simple':
        interest = principal * rate_decimal * time
        total = principal + interest
        return {
            'principal': principal,
            'rate': rate,
            'time': time,
            'type': 'Basit Faiz',
            'interest_earned': round(interest, 2),
            'total_amount': round(total, 2)
        }
    elif type == 'compound':
        total = principal * (1 + rate_decimal / n) ** (n * time)
        interest = total - principal
        return {
            'principal': principal,
            'rate': rate,
            'time': time,
            'type': f'Bileşik Faiz ({n} kez/yıl)',
            'interest_earned': round(interest, 2),
            'total_amount': round(total, 2)
        }
    else:
        return {'error': 'Geçersiz faiz türü. "simple" veya "compound" kullanın.'}
